INSERT INTO external_events VALUES(16,'github','pr_reviewed','1262','https://github.com/bavovna-ua/skymap/pull/1262','Feature/maritime friendly entity','bavovna-ua/skymap','2026-05-18T10:52:30Z','{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1262","repository_url":"https://api.github.com/repos/bavovna-ua/skymap","labels_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1262/labels{/name}","comments_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1262/comments","events_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1262/events","html_url":"https://github.com/bavovna-ua/skymap/pull/1262","id":4405884524,"node_id":"PR_kwDOM-5ssc7ZgTuS","number":1262,"title":"Feature/maritime friendly entity","user":{"login":"seemslikelegit","id":15359283,"node_id":"MDQ6VXNlcjE1MzU5Mjgz","avatar_url":"https://avatars.githubusercontent.com/u/15359283?v=4","gravatar_id":"","url":"https://api.github.com/users/seemslikelegit","html_url":"https://github.com/seemslikelegit","followers_url":"https://api.github.com/users/seemslikelegit/followers","following_url":"https://api.github.com/users/seemslikelegit/following{/other_user}","gists_url":"https://api.github.com/users/seemslikelegit/gists{/gist_id}","starred_url":"https://api.github.com/users/seemslikelegit/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/seemslikelegit/subscriptions","organizations_url":"https://api.github.com/users/seemslikelegit/orgs","repos_url":"https://api.github.com/users/seemslikelegit/repos","events_url":"https://api.github.com/users/seemslikelegit/events{/privacy}","received_events_url":"https://api.github.com/users/seemslikelegit/received_events","type":"User","user_view_type":"public","site_admin":false},"labels":[],"state":"closed","locked":false,"assignees":[],"milestone":null,"comments":0,"created_at":"2026-05-08T11:05:39Z","updated_at":"2026-05-18T10:52:30Z","closed_at":"2026-05-18T10:52:27Z","assignee":null,"author_association":"COLLABORATOR","issue_field_values":[],"type":null,"active_lock_reason":null,"draft":false,"pull_request":{"url":"https://api.github.com/repos/bavovna-ua/skymap/pulls/1262","html_url":"https://github.com/bavovna-ua/skymap/pull/1262","diff_url":"https://github.com/bavovna-ua/skymap/pull/1262.diff","patch_url":"https://github.com/bavovna-ua/skymap/pull/1262.patch","merged_at":"2026-05-18T10:52:27Z"},"body":"## Яку проблему я вирішував?\r\nЯ додав підтримку морського(надводного) типу для дружніх сутностей і можливість їх трекати. До цього в адмінці не було вибору типу, у БД не було окремого поля, а умовні човни позначались як FriendlyUnknown.\r\n\r\n### Які зміни, видимі для користувача, я додав?\r\nЯ додав в адмінці поле типу для дружньої сутності з варіантами повітряний / надводний, а також показ цього поля в списку. Тепер класифікація об''єкта, що рухається із автоматизованого джерела може відбуватись по CAT-62 і буде розпізнано як FriendlyBoat за умови відправки відповідного KV в повідомленні. Для морських дружніх джерел треки тепер отримують окрему категорію FriendlyBoat з локалізацією. Також я обмежив ручну зміну категорії та shadow для таких треків.\r\n\r\n### Як я це впровадив:\r\nЯ додав новий тип maritime для friends у shared/backend типах, схемі config.db і міграції migrate.71.db.sql, а також підняв REQUIRED_DB_USER_VERSION до 71. В адмінці я додав вибір типу при створенні дружньої сутності, відображення типу в list/show та заборонив зміну типу при редагуванні. На бекенді я прокинув поле type у FriendData, використав його в friendRdr для призначення TrackCategory.FriendBoat, доповнив конвертери категорій і CoT XML, а також додав guard-и, щоб для FriendBoat не можна було міняти категорію вручну або ставити shadow. Окремо я додав відсутні локалізаційні ключі та оновив frontend/src/types/i18n.d.ts.\r\n\r\n### Як це перевірити:\r\nРучне тестування\r\n У адмінці створити дружню сутність типу надводний, перевірити що тип зберігається, відображається в списку/картці та не змінюється в edit-формі.\r\n Переконатися, що трек від такого джерела отримує категорію friendly boat, має коректну локалізацію і для нього недоступні ручна зміна категорії та встановлення shadow. Це можна зробити із `mock_friendly_radar`. Також на мапі можна побачити, що такий об''єкт наразі буде мати стандартну іконку, а не звичний літачок.","reactions":{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1262/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1262/timeline","performed_via_github_app":null,"state_reason":null,"score":1}','2026-06-05 10:15:02');
