INSERT INTO external_events VALUES(30,'github','pr_merged','1233','https://github.com/bavovna-ua/skymap/pull/1233','BUG: 🍀 SkyMap:  Проблема з позиціями віджетів на екрані','bavovna-ua/skymap','2026-05-11T13:11:47Z','{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1233","repository_url":"https://api.github.com/repos/bavovna-ua/skymap","labels_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1233/labels{/name}","comments_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1233/comments","events_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1233/events","html_url":"https://github.com/bavovna-ua/skymap/pull/1233","id":4351503317,"node_id":"PR_kwDOM-5ssc7WwyX2","number":1233,"title":"BUG: 🍀 SkyMap:  Проблема з позиціями віджетів на екрані","user":{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false},"labels":[{"id":7590842524,"node_id":"LA_kwDOM-5ssc8AAAABxHMQnA","url":"https://api.github.com/repos/bavovna-ua/skymap/labels/bug","name":"bug","color":"d73a4a","default":true,"description":"Something isn''t working"}],"state":"closed","locked":false,"assignees":[{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false}],"milestone":null,"comments":0,"created_at":"2026-04-29T14:52:45Z","updated_at":"2026-05-11T13:11:50Z","closed_at":"2026-05-11T13:11:47Z","assignee":{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false},"author_association":"COLLABORATOR","issue_field_values":[],"type":null,"active_lock_reason":null,"draft":false,"pull_request":{"url":"https://api.github.com/repos/bavovna-ua/skymap/pulls/1233","html_url":"https://github.com/bavovna-ua/skymap/pull/1233","diff_url":"https://github.com/bavovna-ua/skymap/pull/1233.diff","patch_url":"https://github.com/bavovna-ua/skymap/pull/1233.patch","merged_at":"2026-05-11T13:11:47Z"},"body":"https://trello.com/c/1JPhSE82\r\n\r\n  #### Проблема №1\r\n\r\nПри зменшенні вікна браузера справа великий правий віджет починав виходити за екран, хоча ліворуч від усіх віджетів залишалось вільне місце. Кожен DraggableWrapper незалежно обчислював нову позицію через findClosestFreePosition, яка читала стан DOM в\r\n  один і той самий момент. Жоден з лівіших віджетів не \"знав\", що правий хоче посунутись, і не звільняв місце.\r\n \r\n\r\nhttps://github.com/user-attachments/assets/631284f0-8f12-4f3c-8c53-ed5e807ca6ac\r\n\r\n\r\n\r\n  #### Рішення\r\n\r\nВведено координатор-черга (`scheduleWidgetReposition`), через який тепер проходять усі resize-події від useCalculatePositionOnViewportResize. Замість незалежних одночасних обчислень, координатор обробляє всі віджети послідовно в рамках одного\r\n  setTimeout(0):\r\n\r\n  1. Сортує за правим краєм — найбільш затиснутий (правий) обробляється першим\r\n  2. Веде наростаючий список перешкод: зовнішні елементи (ControlPanel) + нові позиції вже оброблених віджетів\r\n  3. Кожен наступний віджет бачить де вже \"осів\" попередній і каскадно зсувається у вільне місце\r\n\r\n  Коли вільного місця більше немає — віджети виходять за екран, як і очікувалось.\r\n\r\nhttps://github.com/user-attachments/assets/b8b5cad6-8b3a-4c8f-bc83-284b929b28d6\r\n\r\n-----\r\n\r\n   #### Проблема №2                                                                                                                                                           \r\n   \r\n  Якщо вимкнути віджет, заповнити його місце ланцюжком інших віджетів і знову ввімкнути — він рендерився поверх іншого і повертався туди при спробі перемістити. Алгоритм пошуку вільного місця обмежений радіусом 500px і не міг знайти вільний простір на іншому боці екрана.    \r\n\r\nhttps://github.com/user-attachments/assets/bfa7957d-fa22-4b4c-aa59-584d13f73862\r\n  \r\n\r\n   ####  Рішення                                                                                                                                                             \r\n                                                                                                                                                                         \r\n  `findClosestFreePosition.ts`: коли спіральний пошук провалюється і не передано явний `fallbackPosition` (монтування/resize) — запускається глобальне сканування всього viewport. Крок спіралі збільшено з 1 до 5px — усуває затримку ~1с (25× менше ітерацій).  \r\n\r\nhttps://github.com/user-attachments/assets/b24a1c57-ca8b-43cb-b25b-37cc792f33e1\r\n\r\n\r\n----\r\n\r\n#### Проблема №3     \r\n\r\nРух invertX/Y-віджетів при ресайзі. DraggableCombatReportingWidget та DraggableCombatReportingSupervisor використовують invertX/invertY. Їхній CSS right/bottom автоматично переміщував елемент разом із правим/нижнім краєм браузера, тоді як інші віджети лишалися на місці.   \r\n\r\nhttps://github.com/user-attachments/assets/c61c0879-5288-4d60-873b-85f407de318d\r\n\r\n\r\n\r\n####  Рішення     \r\n`useLayoutEffect` в `DraggableWrapper.tsx` конвертує позицію в абсолютні left/top та записує їх як inline-стиль до першого paint — inline перекриває CSS-клас, елемент перестає реагувати на рух краю. При resize ResizeObserver перевіряє чи позиція ще вміщується у viewport і при необхідності оновлює її через Redux.\r\n\r\nhttps://github.com/user-attachments/assets/239f5c8c-2f3f-4d76-9d98-d8c6e8d14d1b\r\n\r\n","reactions":{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1233/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1233/timeline","performed_via_github_app":null,"state_reason":null,"score":1}','2026-06-05 10:15:03');
