?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false}],"milestone":null,"comments":0,"created_at":"2026-04-18T15:00:14Z","updated_at":"2026-04-24T06:25:47Z","closed_at":"2026-04-24T06:25:45Z","assignee":{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false},"author_association":"COLLABORATOR","issue_field_values":[],"type":null,"active_lock_reason":null,"draft":false,"pull_request":{"url":"https://api.github.com/repos/bavovna-ua/skymap/pulls/1196","html_url":"https://github.com/bavovna-ua/skymap/pull/1196","diff_url":"https://github.com/bavovna-ua/skymap/pull/1196.diff","patch_url":"https://github.com/bavovna-ua/skymap/pull/1196.patch","merged_at":"2026-04-24T06:25:45Z"},"body":"https://trello.com/c/veHysX9r\r\n\r\n  Що зроблено\r\n\r\n  **Нова функціональність**\r\n  - Додано перевірку розбіжності між локальною версією застосунку та версією на сервері\r\n  - При виявленні невідповідності показується системна нотифікація `MismatchAppVersionNotification`\r\n  - Версія сервера отримується через WebSocket і зберігається в Redux-стані (`settings`)\r\n  \r\n  \r\n\r\nhttps://github.com/user-attachments/assets/1c7b25e8-88b1-4466-8872-2c9ff2b95760\r\n\r\n\r\n\r\n  **Рефакторинг реєстрації системних нотифікацій**\r\n  - Вся логіка видимості нотифікацій централізована в `systemNotificationConfig.ts` через декларативний механізм `hiddenWhen`\r\n  - `useSystemNotificationRegistry` перенесено в модуль `system_notifications` і спрощено\r\n\r\n  **Рефакторинг структури модуля notifications**\r\n  - Компоненти реорганізовано в субмодулі: `system_notifications/`, `directive_notifications/`, `actionable_notifications`/, `base/`\r\n  - Публічний API модуля спрощено: root `index.ts` скоротився вдвічі\r\n  - Видалено застарілі утиліти та тести\r\n  \r\n  \r\n  ","reactions":{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1196/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1196/timeline","performed_via_github_app":null,"state_reason":null,"score":1}','2026-05-24 16:15:02');
