INSERT INTO external_events VALUES(5551,'github','pr_merged','1095','https://github.com/bavovna-ua/skymap/pull/1095','🔊 Частоти: Менеджер частот (фронт)','bavovna-ua/skymap','2026-05-27T14:38:31Z','{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1095","repository_url":"https://api.github.com/repos/bavovna-ua/skymap","labels_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1095/labels{/name}","comments_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1095/comments","events_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1095/events","html_url":"https://github.com/bavovna-ua/skymap/pull/1095","id":4100437854,"node_id":"PR_kwDOM-5ssc7Ly18I","number":1095,"title":"🔊 Частоти: Менеджер частот (фронт)","user":{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false},"labels":[{"id":7590842534,"node_id":"LA_kwDOM-5ssc8AAAABxHMQpg","url":"https://api.github.com/repos/bavovna-ua/skymap/labels/enhancement","name":"enhancement","color":"a2eeef","default":true,"description":"New feature or request"}],"state":"closed","locked":false,"assignees":[{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false}],"milestone":null,"comments":11,"created_at":"2026-03-19T09:27:19Z","updated_at":"2026-05-27T14:38:33Z","closed_at":"2026-05-27T14:38:31Z","assignee":{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false},"author_association":"COLLABORATOR","issue_field_values":[],"type":null,"active_lock_reason":null,"draft":false,"pull_request":{"url":"https://api.github.com/repos/bavovna-ua/skymap/pulls/1095","html_url":"https://github.com/bavovna-ua/skymap/pull/1095","diff_url":"https://github.com/bavovna-ua/skymap/pull/1095.diff","patch_url":"https://github.com/bavovna-ua/skymap/pull/1095.patch","merged_at":"2026-05-27T14:38:31Z"},"body":"\r\nКартки задачі:\r\nhttps://trello.com/c/szaaQtie\r\nhttps://trello.com/c/S4s28o8W\r\nhttps://trello.com/c/czIGqm1y\r\n\r\nТехнічний опис задачі: https://skyfortress.atlassian.net/wiki/x/AQAHIw\r\n\r\n---\r\n\r\n## Менеджер частот\r\n\r\n### Рефакторинг\r\n\r\n- `CombatReportingForm` — монолітний компонент (~730 рядків) розбито на окремі контроли: `FrequencyFormControl`, `LocationFormControl`, `LostReasonFormControl`, `ResultsFormControl` тощо\r\n- `CombatReportingUser` — перероблено, добавлено `HierarchyTree` з одним айтемом\r\n- `CombatReportingSupervisor` — спрощено та перейменовано\r\n\r\n### Новий функціонал\r\n  - FrequencyTableWidget — новий віджет для перегляду та вибору частот (відео діапазони) з можливістю бачити відображення зайнятих і конфліктних частот\r\n  \r\n #### Диспетчер\r\n<img width=\"677\" height=\"621\" alt=\"Screenshot 2026-05-08 at 10 40 08\" src=\"https://github.com/user-attachments/assets/e38de25b-2fb3-474d-be92-75afa715f5bb\" />\r\n\r\n #### Оператор\r\n<img width=\"653\" height=\"538\" alt=\"Screenshot 2026-05-08 at 10 40 17\" src=\"https://github.com/user-attachments/assets/20328988-03a8-4cd6-af14-29664e5e857b\" />\r\n\r\n----\r\nBackend частина\r\n\r\n\r\n### Яку проблему я вирішував?\r\n\r\n* Не було єдиної та надійної логіки керування відеочастотами під час польотів.\r\n* Відсутній контроль конфліктів частот між підрозділами та вимога обов’язкового вибору частоти для розрахунків.\r\n\r\n### Які зміни я додав?\r\n\r\nРозширив модель `UnitState`:\r\n* `lastUsedVideoFreq` — остання використана відеочастота розрахунку;\r\n* `requireFreqSelection` — прапорець обов’язковості вибору частоти;\r\n* `freqScanner` — список занятих частот в радіусі N км;\r\n* `currentFlight.videoFreq` — частота поточного польоту.\r\n\r\nДодав централізований стан частотної карти `frequencyMap`:\r\n* `frequencies` — активні передавачі частот;\r\n* `scanners` — активні сканери;\r\n* `scannerIndex` — індекс відповідності “частота → сканери, які її бачать”.\r\n\r\nДодав повний набір `frequency-редюсерів`:\r\n* `INIT_FREQ_SCANNERS`\r\n* `START_FREQ_SCANNER`\r\n* `UPDATE_FREQ_SCANNER`\r\n* `STOP_FREQ_SCANNER`\r\n* `RESERVE_FREQ`\r\n* `UPDATE_FREQ`\r\n* `RELEASE_FREQ`\r\n\r\nРозширив Socket Events:\r\n* `START_FLIGHT` тепер приймає `videoFreq`;\r\n* `UPDATE_FLIGHT` підтримує зміну/скидання `videoFreq`.\r\n\r\nДодав обробку помилок при виборі частоти:\r\n* `FREQ_SELECTION_REQUIRED`\r\n* `FREQ_UNAVAILABLE_FOR_RESERVATION`\r\n\r\nОновив БД:\r\n* нове поле `requireFreqSelection` у `units`;\r\n* нове поле `videoFreq` у `flights`;\r\n* нове поле `videoFreq` у `contact_reports_air`;\r\n\r\nОновив форму розрахунку для прапорця `requireFreqSelection`.\r\n<img width=\"645\" height=\"387\" alt=\"Screenshot 2026-05-11 at 06 19 16\" src=\"https://github.com/user-attachments/assets/854ffff2-59e9-46d8-bbde-059b4d62ffd7\" />\r\nОновив звіти по повітряних цілях: додав поле відео частоти, а також у списку додав можливість фільтрації за частотою та експорту в csv\r\n<img width=\"817\" height=\"470\" alt=\"Screenshot 2026-05-13 at 18 08 54\" src=\"https://github.com/user-attachments/assets/f30b2a35-e83c-425d-ad43-4619d7bec05a\" />\r\n\r\n\r\nЯк я це реалізував?\r\n\r\nВиніс частотну логіку в окремий доменний сервіс `FreqMapService`, щоб централізувати правила резервування, оновлення, звільнення частоти та керування сканерами.\r\n\r\nДля геопошуку застосував просторовий індекс GeoCircleIndex поверх RBush:\r\n* окремий індекс для сканерів;\r\n* окремий індекс для активних частот;\r\n\r\nКонфлікт частот перевіряю через смугу каналу:\r\nвикористовую `CHANNEL_BANDWIDTH_MHZ`,\r\nнову частоту не можна резервувати, якщо вона перетинається з уже зайнятими в зоні видимості сканера розрахунку.\r\n\r\nЖиттєвий цикл частоти вбудовано в польоти:\r\n* на `START_FLIGHT`: валідація вимог + резерв частоти + запис у БД/стан;\r\n* на `UPDATE_FLIGHT`: перевірка нової частоти, оновлення або скидання;\r\n* на `END_FLIGHT`: звільнення частоти, збереження в `lastUsedVideoFreq`, очищення `currentFlight`.\r\n\r\nСканери синхронізуються з життєвим циклом розрахунку:\r\n* стартують при переході в ready-стан;\r\n* зупиняються при NOT_READY/видаленні;\r\n* оновлюються при зміні позиції.\r\n\r\nПри ініціалізації стану:\r\n* підтягується остання використана частота з історії польотів;\r\n* ініціалізуються сканери;\r\n* синхронізуються активні польоти та частоти в frequencyMap.","reactions":{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1095/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1095/timeline","performed_via_github_app":null,"state_reason":null,"score":1}','2026-06-05 10:15:03');
