jU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false}],"milestone":null,"comments":1,"created_at":"2026-06-01T14:02:12Z","updated_at":"2026-06-04T14:12:05Z","closed_at":null,"assignee":{"login":"maplemap","id":5664270,"node_id":"MDQ6VXNlcjU2NjQyNzA=","avatar_url":"https://avatars.githubusercontent.com/u/5664270?v=4","gravatar_id":"","url":"https://api.github.com/users/maplemap","html_url":"https://github.com/maplemap","followers_url":"https://api.github.com/users/maplemap/followers","following_url":"https://api.github.com/users/maplemap/following{/other_user}","gists_url":"https://api.github.com/users/maplemap/gists{/gist_id}","starred_url":"https://api.github.com/users/maplemap/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/maplemap/subscriptions","organizations_url":"https://api.github.com/users/maplemap/orgs","repos_url":"https://api.github.com/users/maplemap/repos","events_url":"https://api.github.com/users/maplemap/events{/privacy}","received_events_url":"https://api.github.com/users/maplemap/received_events","type":"User","user_view_type":"public","site_admin":false},"author_association":"COLLABORATOR","issue_field_values":[],"type":null,"active_lock_reason":null,"draft":false,"pull_request":{"url":"https://api.github.com/repos/bavovna-ua/skymap/pulls/1331","html_url":"https://github.com/bavovna-ua/skymap/pull/1331","diff_url":"https://github.com/bavovna-ua/skymap/pull/1331.diff","patch_url":"https://github.com/bavovna-ua/skymap/pull/1331.patch","merged_at":null},"body":"https://trello.com/c/0qHkdy6e\r\n\r\n  Що зроблено:\r\n  - Додано splash-екран у index.html (до монтування React): логотип + локалізоване повідомлення з shimmer-анімацією; розмір адаптивний (min(350px, 85vw))\r\n  - Локаль для splash зчитується з localStorage ще до завантаження бандла\r\n  - user reducer — персистується лише settings.locale через redux-persist з окремим ключем user-locale; решта налаштувань оновлюється з бекенда і не зберігається в локалсторедж\r\n  - App.tsx — видалено WaitingForConfig компонент (замінено на null): очікування перенесено в splash на рівні HTML\r\n  \r\n  Чому FOUT-фікс (останній коміт):\r\n  - app.css інжектиться бандлом і перевизначає @font-face ''Trebuchet MS'' через font-display: swap → splash-**текст миготів і стрибав**\r\n  - Рішення: окрема родина ''Trebuchet MS Bold Splash'' зв''язана з бандленим .ttf у public/fonts/ + preload + font-display: block — шрифт ізольований від глобального CSS застосунку, однаковий для всіх користувачів\r\n  - Зафіксовано line-height: 1.15 і height на <h5>, щоб інжект normalize не зміщував колонку через justify-content: center\r\n\r\nЯк це виглядає зараз\r\n\r\nhttps://github.com/user-attachments/assets/1cf3928c-c4b1-412e-85d8-c0c3cd6f5e4c\r\n\r\n\r\nhttps://github.com/user-attachments/assets/a69b9c44-911b-4d2d-8d72-894e6e8633d4\r\n\r\n\r\n\r\n\r\n\r\n\r\n","reactions":{"url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1331/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/bavovna-ua/skymap/issues/1331/timeline","performed_via_github_app":null,"state_reason":null,"score":1}','2026-06-05 10:15:01');
